{"path":"/app/check_cert.py","content":"#!/usr/bin/env python3
"""Verify a self-signed TLS certificate."""

import sys
import os
from datetime import datetime

try:
    from OpenSSL import crypto
except ImportError:
    # Fallback: parse PEM manually if pyOpenSSL is not available
    def load_cert(path):
        with open(path, "rb") as f:
            return crypto.load_certificate(crypto.FILETYPE_PEM, f.read())

    cert_path = "/app/ssl/server.crt"

    if not os.path.isfile(cert_path):
        print(f"ERROR: Certificate file not found: {cert_path}")
        sys.exit(1)

    try:
        cert = load_cert(cert_path)
    except Exception as e:
        print(f"ERROR: Failed to load certificate: {e}")
        sys.exit(1)

    # Extract Common Name
    cn = None
    for attr in cert.get_subject():
        if attr.type == crypto.X509Name.COMMONNAME:
            cn = attr.value
            break

    # Get expiration date
    not_after = cert.get_notAfter().decode("utf-8")
    # Parse OpenSSL date format: "Apr 24 07:41:41 2027 GMT"
    try:
        exp_date = datetime.strptime(not_after, "%b %d %H:%M:%S %Y %Z")
    except ValueError:
        exp_date = datetime.strptime(not_after.rstrip(" GMT"), "%b %d %H:%M:%S %Y")

    print(f"Common Name (CN): {cn}")
    print(f"Expiration Date: {exp_date.strftime('%Y-%m-%d')}")
    print("Certificate verification successful")
"}
